    parseProcedimiento() {
      if (!this.procedimientoText.trim()) {
        this.showStatus('❌ Por favor ingresa la descripción del procedimiento', 'error');
        return;
      }
      try {
        // Procesar el texto en párrafos
        const paragraphs = this.procedimientoText.split('\n\n').filter(p => p.trim() !== '');
        const table = [];
        let stepNumber = 1;
        paragraphs.forEach(paragraph => {
          const lines = this.processParagraph(paragraph.trim());
          lines.forEach(line => {
            if (line.trim()) {
              const responsible = this.extractResponsible(line);
              const activity = this.extractActivity(line, responsible);
              if (responsible || activity) {
                table.push({
                  number: `${stepNumber}`,
                  who: responsible,
                  activity: activity
                });
                stepNumber++;
              }
            }
          });
