      }
    },
    processParagraph(paragraph) {
      // Dividir el párrafo en oraciones
      const sentences = paragraph.split(/[.!?]+/).filter(s => s.trim() !== '');
      const processedLines = [];
      sentences.forEach(sentence => {
        const trimmedSentence = sentence.trim();
        if (!trimmedSentence) return;

        // Procesar oraciones condicionales
        if (trimmedSentence.includes(';') || trimmedSentence.includes('pero') || trimmedSentence.includes('sin embargo')) {
          // Dividir oraciones compuestas
          const parts = trimmedSentence.split(/[;]|pero|sin embargo/).filter(p => p.trim() !== '');
          parts.forEach(part => {
            processedLines.push(this.cleanSentence(part));
          });
        } else if (trimmedSentence.includes('Si ') || trimmedSentence.includes('si ') || trimmedSentence.includes('Cuando ') || trimmedSentence.includes('cuando ')) {
          // Procesar condiciones
          this.processConditionalSentence(trimmedSentence, processedLines);
        } else {
          // Oración normal
          processedLines.push(this.cleanSentence(trimmedSentence));
        }
      });
      return processedLines;
    },
    processConditionalSentence(sentence, processedLines) {
      const cleanSentence = this.cleanSentence(sentence);

      // Detectar patrones condicionales comunes
      if (cleanSentence.includes(' si ') || cleanSentence.startsWith('Si ') || cleanSentence.startsWith('si ')) {
        // Dividir en condición y consecuencia
        const conditionalParts = cleanSentence.split(/[,]|;/).filter(p => p.trim() !== '');
        conditionalParts.forEach(part => {
          const trimmedPart = part.trim();
          if (trimmedPart) {
            processedLines.push(trimmedPart);
          }
        });
      } else {
        processedLines.push(cleanSentence);
      }
    },
    cleanSentence(sentence) {
      // Limpiar y formatear la oración
      return sentence.replace(/^[,.\s]+/, '') // Quitar comas y puntos al inicio
