    extractResponsible(line) {
      // Patrones mejorados para detectar responsables en texto descriptivo
      const patterns = [/^el (\w+\s?\w*)\s/i, /^la (\w+\s?\w*)\s/i, /^los (\w+\s?\w*)\s/i, /^las (\w+\s?\w*)\s/i, /^un (\w+\s?\w*)\s/i, /^una (\w+\s?\w*)\s/i, /^(\w+\s?\w*)\s(revisa|envía|realiza|verifica|corrige|aprueba|autoriza|elabora|analiza|efectúa|notifica|solicita|confirma)/i, /^(\w+\s?\w*)\s(recibe|entrega|completa|procede|marca)/i, /(\w+\s?\w*)\s(revisa|envía|realiza|verifica|corrige|aprueba)/i];
      for (const pattern of patterns) {
        const match = line.match(pattern);
        if (match) {
          const responsible = match[1] || match[2];
          if (responsible && !this.isCommonWord(responsible)) {
            return this.capitalizeFirstLetter(responsible);
          }
        }
      }
      return '';
