    isCommonWord(word) {
      const commonWords = ['proceso', 'caso', 'pago', 'factura', 'documento', 'lista', 'producto', 'proveedor'];
      return commonWords.includes(word.toLowerCase());
    },
    extractActivity(line, responsible) {
      if (!responsible) return this.capitalizeFirstLetter(line);

      // Remover el responsable del inicio de la línea
      const patterns = [new RegExp(`^el ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^la ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^los ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^las ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^un ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^una ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^${responsible.toLowerCase()}\\s+`, 'i')];
      let activity = line;
      for (const pattern of patterns) {
        activity = activity.replace(pattern, '');
      }
      return this.capitalizeFirstLetter(activity);
